#include <stdio.h>
#include <ctype.h>
#include <string.h>
#include <stdbool.h>

int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    getchar(); // consume newline after T
    while(T--){
        char line[1005];
        if(!fgets(line,sizeof(line),stdin)) break;
        line[strcspn(line,"\n")]='\0'; // remove trailing newline
        int len=strlen(line);
        int i=0;
        while(i<len){
            int start=i;
            while(i<len && line[i]!=' ') i++;
            int end=i; // one past last character of the word
            bool isAcronym=true;
            for(int j=start;j<end;++j){
                if(islower((unsigned char)line[j])){ isAcronym=false; break; }
            }
            if(!isAcronym && start<end){
                line[start]=toupper((unsigned char)line[start]);
                for(int j=start+1;j<end;++j) line[j]=tolower((unsigned char)line[j]);
            }
            if(i<len && line[i]==' ') i++; // skip space
        }
        printf("%s\n",line);
    }
    return 0;
}

