#include <bits/stdc++.h>
using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    string line; getline(cin,line); // consume endline
    while(T--){
        getline(cin,line);
        string result;
        size_t i=0;
        while(i<line.size()){
            size_t start=i;
            while(i<line.size() && line[i]!=' ') ++i;
            size_t end=i;
            bool isAcronym=true;
            for(size_t j=start;j<end;++j){
                if(islower(static_cast<unsigned char>(line[j]))){ isAcronym=false; break; }
            }
            if(isAcronym){
                result.append(line.substr(start,end-start));
            }else if(start<end){
                result.push_back(toupper(static_cast<unsigned char>(line[start])));
                for(size_t j=start+1;j<end;++j) result.push_back(tolower(static_cast<unsigned char>(line[j])));
            }
            if(i<line.size() && line[i]==' '){ result.push_back(' '); ++i; }
        }
        cout<<result<<'\n';
        result.clear();
    }
    return 0;
}

