import sys

def title_case(s):
    words = s.split(' ')
    res = []
    for w in words:
        if w.isupper():
            res.append(w)
        else:
            if w:
                res.append(w[0].upper() + w[1:].lower())
            else:
                res.append('')
    return ' '.join(res)

data = sys.stdin.read().splitlines()
if not data:
    sys.exit()
T = int(data[0].strip())
out = []
for i in range(1, T+1):
    out.append(title_case(data[i].rstrip('\n')))
print('\n'.join(out))

